import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            int[] a = new int[N];
            for (int i = 0; i < N; i++) a[i] = fs.nextInt();
            Arrays.sort(a);
            HashMap<Integer,Integer> freq = new HashMap<>();
            for (int x : a) freq.put(x, freq.getOrDefault(x,0)+1);
            boolean ok = true;
            int max = a[N-1];
            if (freq.get(max) == 2) ok = false;
            for (int cnt : freq.values()) if (cnt > 2) {ok = false; break;}
            if (!ok) {out.append("NO\n"); continue;}
            ArrayList<Integer> inc = new ArrayList<>(freq.keySet());
            Collections.sort(inc);
            ArrayList<Integer> dec = new ArrayList<>();
            for (int i = inc.size()-1; i >=0; i--) {
                int v = inc.get(i);
                if (freq.get(v) == 2) dec.add(v);
            }
            out.append("YES\n");
            for (int i = 0; i < inc.size(); i++) {
                if (i>0) out.append(' ');
                out.append(inc.get(i));
            }
            for (int v : dec) out.append(' ').append(v);
            out.append('\n');
        }
        System.out.print(out.toString());
    }
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in){this.in=in;}
        private int readByte() throws IOException {
            if (ptr >= len) {len = in.read(buffer); ptr = 0; if (len <= 0) return -1;}
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do {c = readByte();} while (c <= ' ');
            if (c == '-') {sign = -1; c = readByte();}
            while (c > ' ') {val = val*10 + c - '0'; c = readByte();}
            return val*sign;
        }
    }
}

