const fs = require('fs');
const input = fs.readFileSync(0,'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let out = [];
for(let t=0;t<T;t++){
  const N = Number(input[idx++]);
  let arr = new Array(N);
  for(let i=0;i<N;i++) arr[i] = Number(input[idx++]);
  arr.sort((a,b)=>a-b);
  const freq = new Map();
  for(const x of arr){freq.set(x,(freq.get(x)||0)+1);}
  let ok = true;
  const maxVal = arr[N-1];
  if(freq.get(maxVal)===2) ok = false;
  for(const cnt of freq.values()) if(cnt>2){ok=false;break;}
  if(!ok){out.push('NO');continue;}
  const inc = Array.from(freq.keys()).sort((a,b)=>a-b);
  const dec = [];
  for(let i=inc.length-1;i>=0;i--){const v=inc[i];if(freq.get(v)===2) dec.push(v);}
  out.push('YES');
  out.push(inc.concat(dec).join(' '));
}
console.log(out.join('\n'));
